static u32 entry_count;
static int loaded;
/* open-address map: index into entries, 0xffffffff empty */
static u32 name_map[4096];

static u32 tok_hash(const u8 *tok) {
    u32 h = 2166136261u;
    for (int i = 0; i < 32; i++) { h ^= tok[i]; h *= 16777619u; }
    return h;
