    load_index();
    u32 h = tok_hash(tok) & 4095u;
    for (u32 n = 0; n < 4096; n++) {
        u32 s = (h + n) & 4095u;
        u32 idx = name_map[s];
        if (idx == 0xffffffffu) break;
        if (!memcmp(entries[idx].token, tok, 32)) return entries[idx].name;
