/* Very small path subset: M/m L/l H/h V/v Z/z and numbers. Absolute after M. */
static int svg_parse_num(const char **pp, float *out) {
    const char *p = *pp;
    while (*p == ' ' || *p == ',' || *p == '\n' || *p == '\r' || *p == '\t') p++;
    char *end = 0;
    float v = strtof(p, &end);
    if (end == p) return 0;
    *out = v;
    *pp = end;
    return 1;
}

