        dxgfx_draw_line(x0 + pad * 0.5f, y0, x0 + pad * 0.5f, y1, argb, stroke);
        dxgfx_draw_line(x0 + pad * 0.5f, y0, x1, cy, argb, stroke);
        dxgfx_draw_line(x0 + pad * 0.5f, y1, x1, cy, argb, stroke);
