native = {bytes.fromhex(v): k for k, v in man["native"].items()}
logical = {}
for n, v in man["modules"].items():
    logical[bytes.fromhex(v["key"])] = ("mod", n, v.get("role"))
for n, v in man["actions"].items():
    logical[bytes.fromhex(v["key"])] = ("act", n, None)
logical[bytes.fromhex(man["program_key"])] = ("prog", "program", None)

def disasm(path, limit=80):
    raw = open(path, "rb").read()
    off = 0
    rows = []
    while off + 32 <= len(raw):
        tok = raw[off:off+32]
        if tok == bytes(32):
            break
        pn = struct.unpack_from("<I", raw, off+32)[0]
        payload = raw[off+36:off+36+pn]
        if tok in native:
            name = native[tok]
        elif tok in logical:
            name = logical[tok][1]
        else:
            name = tok.hex()[:12]
        rows.append((name, pn, payload))
        off += 36 + pn
    return rows

print("=== PROGRAM ===")
for i,(n,pn,p) in enumerate(disasm("first_program_block.bin")):
    print(f"{i:2d} {n} pn={pn}")

print("\n=== MODULES/PARTS (by size, specialized first) ===")
mods = []
for n, meta in man["modules"].items():
    path = f"atomic_module_blocks/{n}.bin"
    if not os.path.exists(path): continue
    rows = disasm(path)
    mods.append((len(open(path,"rb").read()), n, meta.get("role"), rows))
for size,n,role,rows in sorted(mods, reverse=True):
    print(f"\n[{role}] {n} size={size} ins={len(rows)}")
    for i,(nm,pn,p) in enumerate(rows[:25]):
        extra = ""
        if pn and nm in ("const_payload","f32_const","key_pressed","key_down","mouse_button_down","mouse_button_pressed","views","cond_payload","var_read_payload","var_write_payload","var_set_payload"):
            if nm in ("key_pressed","key_down","mouse_button_down","mouse_button_pressed") and pn>=4:
                extra = f" vk={struct.unpack_from('<I',p)[0]}"
            elif nm=="f32_const" and pn>=4:
                extra = f" f={struct.unpack_from('<f',p)[0]}"
            elif nm=="const_payload" and pn==4:
                extra = f" u={struct.unpack_from('<I',p)[0]}"
            elif nm=="views" and pn>=36:
                op=struct.unpack_from("<I",p,32)[0]; extra=f" op={op}"
            elif nm=="cond_payload" and pn>=32:
                t=p[:32]; extra=" ->"+(native.get(t) or (logical.get(t,[None,t.hex()[:8]])[1]))
            elif nm.endswith("payload") and pn:
                extra=f" [{pn}B]"
        print(f"  {i:2d} {nm}{extra}")

print("\n=== ACTIONS ===")
for n, meta in sorted(man["actions"].items()):
