    for i,(nm,pn,p) in enumerate(rows):
        print(f"  {i:2d} {nm} pn={pn}")

print("\nnatives used:", sorted(man["native"].keys()))
print("modules:", len(man["modules"]), "actions:", len(man["actions"]))
